# Deobfuscated Code

After decoding the string table (base64 with XOR) and resolving all references, here's the clean version:

```javascript
var TAU = 6.283;
var PHI = 1.618;
var SQRT1_2 = 0.707;

var config = {
  attraction: 4000,          // repulsion force constant
  springCoeff: 0.004,        // spring coefficient
  amplification: 0.92,       // velocity damping factor
  centerGravity: 0.0003,     // centering force
  streamCount: 40,           // max particles
  streamDecay: 0.04,         // particle drag
  theta: 0.06               // camera smoothing
};

// --- Nodes ---
var nodes = [
  { id: 'hub',       label: 'Hub',       r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',     label: 'Alpha',     r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',      label: 'Beta',      r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',     label: 'Gamma',     r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',     label: 'Delta',     r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon',   label: 'Epsilon',   r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// --- Edges (springs) ---
var edges = [
  { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

var camera       = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };
var particles = [];
var tick = 0;

function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// --- PHYSICS: This is a force-directed graph layout ---
function updatePhysics() {
  // 1) Node-node REPULSION (Coulomb-like)
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.attraction / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) Edge SPRING attraction (Hooke's law)
  for (var e = 0; e < edges.length; e++) {
    var na = findNode(edges[e].a);
    var nb = findNode(edges[e].b);
    if (!na || !nb) continue;
    var dx = nb.x - na.x;
    var dy = nb.y - na.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || config.springCoeff) * displacement;
    na.vx += (dx / dist) * force;
    na.vy += (dy / dist) * force;
    nb.vx -= (dx / dist) * force;
    nb.vy -= (dy / dist) * force;
  }

  // 3) Integration + centering gravity + velocity damping
  for (var n = 0; n < nodes.length; n++) {
    nodes[n].vx += (400 - nodes[n].x) * config.centerGravity;
    nodes[n].vy += (300 - nodes[n].y) * config.centerGravity;
    nodes[n].vx *= config.amplification;  // damping
    nodes[n].vy *= config.amplification;
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// --- Spawn a particle from a random node ---
function spawnParticle() {
  if (particles.length >= config.streamCount) return;
  var node = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT1_2;
  particles.push({
    x: node.x,
    y: node.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI) * SQRT1_2
  });
}

// --- Update particles (move, decay, cull) ---
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    p.age++;
    p.vx *= (1 - config.streamDecay * 0.125);
    p.vy *= (1 - config.streamDecay * 0.125);
    p.x += p.vx;
    p.y += p.vy;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

// --- Smooth camera follow ---
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.theta;
  camera.y += (cameraTarget.y - camera.y) * config.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.theta;
}

// --- Main loop ---
function mainLoop() {
  updatePhysics();
  updateParticles();
  updateCamera();
  if (tick % 3 === 0) spawnParticle();
  tick++;
}

setInterval(mainLoop, 16); // ~60fps
```

## Summary

This is a **force-directed graph simulation** with:

- **6 nodes** (Hub, Alpha, Beta, Gamma, Delta, Epsilon) connected by **8 spring edges**
- **Coulomb repulsion** between all node pairs (inverse-square law)
- **Hooke's law springs** along edges pulling connected nodes toward rest lengths
- **Center gravity** pulling nodes toward (400, 300)
- **Velocity damping** (0.92×) each frame for stability
- **Ambient particles** spawned from random nodes, drifting outward and fading
- **Smooth camera** interpolation toward a target

The `amplification` field name is misleading — it's actually a **damping/friction** factor (0.92), and `attraction` is actually the **repulsion** constant. The algorithm is a standard spring-electrical force-directed layout running at ~60fps.
